checker_dsl:
EXISTS (`statement S`) {
  AND {
    EXISTS (`control structure C`, `statement T`) {
      AND {
        EXISTS (`integer BODYCOL`, `integer SUCCCOL`, `integer CTRLCOL`, `integer BODYLINE`, `integer SUCCLINE`) {
          AND {
            AND {
              (`S is not an instance of BlockStmt`),
              OR {
                EXISTS (`IfStmt C_IF`) {
                  AND {
                    (`C_IF = C`),
                    OR {
                      AND {
                        (`S = C_IF.getElse()`),
                        (`S is not an instance of IfStmt`)
                      },
                      AND {
                        (`S = C_IF.getThen()`),
                        NOT { EXISTS (`C_IF.getElse()`) { (`true`) } }
                      }
                    }
                  }
                },
                EXISTS (`LoopStmt C_LOOP`) {
                  AND {
                    (`C_LOOP = C`),
                    (`C_LOOP is not an instance of DoStmt`),
                    (`S = C_LOOP.getBody()`)
                  }
                }
              }
            },
            EXISTS (`statement S_FINAL`) {
              AND {
                (`S_FINAL is reachable from S via zero or more getParent() where parent is not a BlockStmt and not a SwitchStmt`),
                OR {
                  EXISTS (`BlockStmt B`, `integer I`) {
                    AND {
                      (`B.getStmt(I) = S_FINAL`),
                      (`B.getStmt(I + 1) = T`)
                    }
                  },
                  EXISTS (`SwitchStmt B`, `integer I`) {
                    AND {
                      (`B.getStmt(I) = S_FINAL`),
                      (`B.getStmt(I + 1) = T`)
                    }
                  }
                }
              }
            },
            AND {
              (`BODYCOL = S.getLocation().getStartColumn()`),
              (`SUCCCOL = T.getLocation().getStartColumn()`),
              (`BODYLINE = S.getLocation().getStartLine()`),
              (`SUCCLINE = T.getLocation().getStartLine()`)
            },
            OR {
              (`BODYCOL = SUCCCOL`),
              (`BODYLINE = SUCCLINE`)
            },
            OR {
              (`CTRLCOL < BODYCOL`),
              (`BODYCOL < SUCCCOL`)
            },
            OR {
              (`CTRLCOL = C.getLocation().getStartColumn()`),
              EXISTS (`IfStmt S2`) {
                AND {
                  (`C is reachable from S2 via one or more getElse()`),
                  (`CTRLCOL = S2.getLocation().getStartColumn()`)
                }
              }
            }
          }
        },
        NOT {
          OR {
            (`S is an instance of JumpStmt`),
            (`S is an instance of ReturnStmt`),
            (`S is an instance of ThrowStmt`)
          }
        },
        (`T is not an instance of EmptyStmt`),
        (`T is not an instance of LocalTypeDeclStmt`)
      }
    }
  }
}
